/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt_sl: '[gia_nt]:=([gia_nt] == 0 ? ([so_luong] != 0 ? ([tien_nt]/[so_luong]) : 0) : [gia_nt])',
    gia_sl: '[gia]:=([gia] == 0 ? ([so_luong] != 0 ? ([tien]/[so_luong]) : 0) : [gia])',

    t_so_luong: ['t_so_luong', 'so_luong'],

    gia: '[gia]:=[gia_nt]*[$ty_gia]',
    tien_nt: '[tien_nt]:=[so_luong]*[gia_nt]',
    tien: '[tien]:=[so_luong]*[gia]',
    tien_tg: '[tien]:=[tien_nt]*[$ty_gia]',

    t_thue: '[t_thue]:=[t_tien]*[thue_suat]/100',
    t_thue_nt: '[t_thue_nt]:=[t_tien_nt]*[thue_suat]/100',

    t_tien: ['t_tien', 'tien'],
    t_tien_nt: ['t_tien_nt', 'tien_nt'],

    t_tt: '[t_tt]:=[t_tien]+[t_thue]',
    t_tt_nt: '[t_tt_nt]:=[t_tien_nt]+[t_thue_nt]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_dvcs', 'stt_rec'];
  udf$Detail$(g, true);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
}
function onChange$GridVoucherDetail$Item(o) {
  var g = o.grid;
  g.setItemGridBehavior(o,[['ma_lo','','',false]]);
  g.request(o, 'Item', 'Item', ['ma_vt', 'ma_kho', 'ma_vi_tri', ['action', 'Decimal', g.get_element().parentForm._action == 'Edit' ? 1 : 0]], g.$h, true);
}
function onChange$GridVoucherDetail$UOM(o) {
  var g = o.grid;
  g.request(o, 'UOM', 'UOM', ['ma_vt', 'ma_kho', 'dvt', 'ma_vi_tri', 'ma_lo', ['action', 'Decimal', g.get_element().parentForm._action == 'Edit' ? 1 : 0]], g.$h, true);
}
function onChange$GridVoucherDetail$Site(o) {
  var g = o.grid;
  g.setItemGridBehavior(o,[['ma_vi_tri','','',false]]);
  g.request(o, 'Site', 'Site', ['ma_kho', 'ma_vt', 'ma_lo', 'dvt', 'he_so', ['action', 'Decimal', g.get_element().parentForm._action == 'Edit' ? 1 : 0]], g.$h, true);
}
function onChange$GridVoucherDetail$Location(o) {
  var g = o.grid;
  if (g._stockViewType == 1 || g._stockViewType == 3 || (!o.value)) return;
  g.request(o, 'Location', 'Location', ['ma_vt', 'he_so', 'ma_kho', 'ma_vi_tri', 'ma_lo', ['action', 'Decimal', g.get_element().parentForm._action == 'Edit' ? 1 : 0]], g.$h, true);
}
function onChange$GridVoucherDetail$Lot(o) {
  var g = o.grid;
  if (g._stockViewType == 1 || g._stockViewType == 2 || (!o.value)) return;
  g.request(o, 'Lot', 'Lot', ['ma_vt', 'he_so', 'ma_kho', 'ma_vi_tri', 'ma_lo', ['action', 'Decimal', g.get_element().parentForm._action == 'Edit' ? 1 : 0]], g.$h, true);
}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt, g.$a.tien], [g.$a.t_so_luong, g.$a.t_tien_nt, g.$a.t_tien], [g.$a.t_thue_nt, g.$a.t_thue, g.$a.t_tt_nt, g.$a.t_tt], 'gia_nt');
      break;
    case 'gia_nt':
      g.validExpression(o, [g.$a.gia, g.$a.tien_nt, g.$a.tien], [g.$a.t_tien_nt, g.$a.t_tien], [g.$a.t_thue_nt, g.$a.t_thue, g.$a.t_tt_nt, g.$a.t_tt], 'tien_nt');
      break;
    case 'tien_nt':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt_sl, g.$a.gia]);
      g.validExpression(o, [g.$a.tien_tg], [g.$a.t_tien_nt, g.$a.t_tien], [g.$a.t_thue_nt, g.$a.t_thue, g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'gia':
      g.validExpression(o, [g.$a.tien], [g.$a.t_tien], [g.$a.t_thue, g.$a.t_tt], 'tien');
      break;
    case 'tien':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_sl]);
      g.validExpression(o, null, [g.$a.t_tien], [g.$a.t_thue, g.$a.t_tt]);
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  var l = f.getItemValue('loai_ct'), v1 = (!f._$inStockType) && ((l == 1) || (l == 6)), v2 = (!f._$inStockType) && ((l == 6) || (l == 9));
  switch (action) {&ScriptCheckGridAction;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      if (v1 && !(g.validRowExpression('kt_so', '[stt_rec_kt] == ""'))) break;
      if (v2 && !(g.validRowExpression('hd_so', '[stt_rec_hd] == ""'))) break;

      if (!(g.validRowExpression('so_luong', '([gia_ton] != 3) || ([gia_ton] == 3 && [so_luong] != 0)'))) break;
      if (g._tracked$Lot && !(g.validRowExpression('ma_lo', '(![lo_yn]) || ([ma_lo] != "")'))) break;
      if (g._tracked$Location) g.validRowExpression('ma_vi_tri', '(![vi_tri_yn]) || ([ma_vi_tri] != "")');
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ma_kh, ngay_lct')) break;
      switch (e.type.Value) {
        case '10':
          g.showForm('PSReceiptFilter');
          break;
        case '20':
          if (v1) break;
          g.showForm('PSQualityControlFilter');
          break;
        case '40':
          if (v2) break;
          g.showForm('PSInvoiceDomesticFilter');
          break;
        case '50':
          if (v2) break;
          g.showForm('PSInvoiceImportFilter');
          break;
        case '70':
          if (!f._$inStockType) break;
          g.showForm('PSPhysicalFilter');
          break;
        default:
          break;
      }
      break;
    case 'Copying':
      var fields = 'pn_so, pn_ln, hd_so, hd_ln, kt_so, kt_ln, stt_rec_pn, stt_rec0pn, stt_rec_hd, stt_rec0hd, stt_rec_kt, stt_rec0kt, stt_rec_dh, stt_rec0dh';
      &ScriptWhenTransactionEmptyField;
      if (fields != '') set$Voucher$EmptyExternalField(g, fields);break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$GridVoucherDetail$RowChange(g, f) {
  g.executeAggregate([g.$a.t_so_luong]);
  g.executeAggregate([g.$a.t_tien_nt, g.$a.t_tien]);
  f.executeExpression([g.$a.t_thue_nt, g.$a.t_thue, g.$a.t_tt_nt, g.$a.t_tt]);
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[0].Value == '' ? true : null), t = (result[0].Value == '' ? 'false' : 'true');
      g.setItemGridBehavior(o, [
        ['ma_lo', '', null, null],
        ['ma_kho', result[0].Value, '', true],
        ['ma_vi_tri', result[1].Value, '', v],
        ['dvt', result[2].Value, '', true],
        ['he_so', result[3].Value, null, null],
        ['tk_vt', result[4].Value, '', true],
        ['gia_ton', result[5].Value, null, null],
        ['vi_tri_yn', [result[6].Value, t], null, null],
        ['lo_yn', result[7].Value, null, null],
        ['ton13', result[11].Value, null, null]
      ]);
      g.live(o, 'dvt');
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, '', true], ['ton13', result[1].Value, null, null]]);
      break;
    case 'Site':
      g.setItemGridBehavior(o, [['tk_vt', result[0].Value, '', true], ['ma_vi_tri', '', '', null], ['vi_tri_yn', result[1].Value, null, null], ['ton13', result[2].Value, null, null]]);
      break;
    case 'Location':
    case 'Lot':
      g.setItemGridBehavior(o, [['ton13', result[0].Value, null, null]]);
      break;
    default:
      break;
  }
}
